(function () {
'use strict';

var m   = appsmith.model || {};
var ctx = m.context   || {};
var bk  = m.bookings  || {};
var pil = m.piloten   || {};
var cmp = m.composite || {};
var cov = m.coverage  || {};
var wr  = m.winRate   || {};
var act = m.activity  || {};
var st  = m.stale     || {};
var com = ctx.commit  || {};
var wk  = ctx.werktage || {};
var wow = cov.wow     || {};
var l30 = act.l30     || {};

function clamp(v, lo, hi) {
  lo = lo == null ? 0 : lo;
  hi = hi == null ? 100 : hi;
  return Math.max(lo, Math.min(hi, v || 0));
}
function sc(v) {
  if (v >= 80) return 'var(--green)';
  if (v >= 60) return 'var(--amber)';
  return 'var(--red)';
}
function scCls(v) {
  if (v >= 80) return 'c-green';
  if (v >= 60) return 'c-amber';
  return 'c-red';
}
function eur(n) {
  if (n == null || isNaN(n)) return '\u2014';
  var abs = Math.abs(n), sign = n < 0 ? '-' : '';
  if (abs >= 1e6) return sign + '\u20ac' + (abs / 1e6).toFixed(1).replace(/\.0$/, '') + 'M';
  if (abs >= 1e3) return sign + '\u20ac' + Math.round(abs / 1e3) + 'k';
  return sign + '\u20ac' + Math.round(abs);
}
function pct(v) { return Math.round(v || 0) + '%'; }
function arrowHtml(t) {
  if (!t) return '';
  var cls = t.cls === 'green' ? 'arrow-up' : t.cls === 'red' ? 'arrow-dn' : 'arrow-eq';
  return '<span class="funnel-arr ' + cls + '">' + (t.arrow || '') + '</span>';
}

function fbar(actual, hr, commit) {
  var a  = clamp(actual);
  var h  = Math.round(hr || 0);
  var hv = clamp(h, 0, 100);
  var av = clamp(a, 0, 100);
  var cv = commit > 0 ? clamp(commit, 0, 100) : 0;
  var hrStart = Math.min(av, hv);
  var hrWidth = Math.max(0, hv - av);
  var color   = sc(a);
  var cls     = scCls(a);
  var showHr  = h > 0 && h !== a;
  var showCmt = commit > 0;
  var delta   = (showCmt && h > 0) ? Math.round(commit - h) : null;
  var deltaHtml = '';
  if (delta !== null && delta !== 0) {
    var dCls = delta > 0 ? 'd-pos' : 'd-neg';
    var dSign = delta > 0 ? '+' : '';
    deltaHtml = '<span class="fbar-l-delta ' + dCls + '">' + dSign + delta + '%</span>';
  }
  var showLabels = showHr || showCmt;
  var labelsHtml = showLabels
    ? '<div class="fbar-labels">'
    +   (showHr ? '<span class="fbar-l-hr">\u2192 ' + h + '% HR</span>' : '')
    +   (showCmt ? '<span class="fbar-l-cmt">| ' + Math.round(commit) + '% CMT</span>' : '')
    +   deltaHtml
    + '</div>'
    : '';
  return '<div class="fbar">'
    + '<div class="fbar-track">'
    +   '<div class="fbar-actual" style="width:' + av + '%;background:' + color + ';"></div>'
    +   (showHr && hrWidth > 0 ? '<div class="fbar-hr" style="left:' + hrStart + '%;width:' + hrWidth + '%;"></div>' : '')
    +   (showCmt ? '<div class="fbar-pin" style="left:' + cv + '%;"></div>' : '')
    + '</div>'
    + labelsHtml
    + '</div>';
}

function svgRing(compAtt, bkAtt, pilAtt) {
  var rings = [
    { r: 68, v: clamp(compAtt), color: sc(compAtt), delay: '0ms' },
    { r: 55, v: clamp(bkAtt),   color: sc(bkAtt),   delay: '90ms' },
    { r: 42, v: clamp(pilAtt),  color: sc(pilAtt),  delay: '180ms' },
  ];
  var arcs = rings.map(function (ring) {
    var circ   = parseFloat((2 * Math.PI * ring.r).toFixed(1));
    var offset = parseFloat((circ * (1 - ring.v / 100)).toFixed(1));
    return '<circle class="ring-track" r="' + ring.r + '" cx="0" cy="0"/>'
      + '<circle class="ring-arc" r="' + ring.r + '" cx="0" cy="0"'
      + ' stroke="' + ring.color + '"'
      + ' stroke-dasharray="' + circ + ' ' + circ + '"'
      + ' stroke-dashoffset="' + circ + '"'
      + ' style="transform:rotate(-90deg);--circ:' + circ + ';--target:' + offset
      + ';animation:ring-fill .85s var(--smooth) ' + ring.delay + ' forwards;"/>';
  }).join('');
  return '<svg class="ring-svg" width="170" height="170" viewBox="-85 -85 170 170">'
    + arcs
    + '<text class="ring-center-val" x="0" y="-8">' + Math.round(compAtt) + '%</text>'
    + '<text class="ring-center-sub" x="0" y="16">Composite</text>'
    + '</svg>';
}

function renderRibbon() {
  var ql   = ctx.quarterLabel || '\u2014';
  var pp   = ctx.progressPct  || 0;
  var done = wk.done  || 0;
  var tot  = wk.total || 0;
  var pace = ctx.pace     || 0;
  var need = ctx.neededDRR || 0;
  var drrC = com.drrToCommit || 0;
  var onTr = ctx.onTrack;
  var hist = ctx.isHistorical;

  var today  = new Date();
  var days   = ['So','Mo','Di','Mi','Do','Fr','Sa'];
  var months = ['Jan','Feb','M\u00e4r','Apr','Mai','Jun','Jul','Aug','Sep','Okt','Nov','Dez'];
  var ds = days[today.getDay()] + ', ' + today.getDate() + '. ' + months[today.getMonth()];

  var hasData    = (bk.target || 0) > 0;
  var paceColor  = onTr ? 'var(--green)' : (hasData ? 'var(--red)' : 'var(--text3)');
  var drrCColor  = drrC >= 0 ? 'var(--green)' : 'var(--red)';
  var drrCSign   = drrC >= 0 ? '+' : '';

  var histBadge = hist ? '<span class="tag tag-amber" style="margin-left:4px">\ud83d\udcc5 Historisch</span>' : '';
  var drrStats = hasData
    ? '<div class="rib-sep"></div>'
    +   '<div class="rib-kv">'
    +     '<span class="rib-kv-val" style="color:' + paceColor + '">' + eur(pace) + '</span>'
    +     '<span class="rib-kv-lbl">DRR Ist</span>'
    +   '</div>'
    +   '<div class="rib-sep"></div>'
    +   '<div class="rib-kv">'
    +     '<span class="rib-kv-val" style="color:var(--sky)">' + eur(need) + '</span>'
    +     '<span class="rib-kv-lbl">DRR Needed</span>'
    +   '</div>'
    +   (com.amount > 0
    +     ? '<div class="rib-sep"></div><div class="rib-kv">'
    +       + '<span class="rib-kv-val" style="color:' + drrCColor + '">' + drrCSign + eur(drrC) + '</span>'
    +       + '<span class="rib-kv-lbl">DRR\u2192Commit</span>'
    +       + '</div>'
    +     : '')
    : '<span class="rib-kv-lbl" style="margin-left:4px;color:var(--text3)">Daten werden geladen\u2026</span>';

  document.getElementById('ribbon').innerHTML =
    '<div class="rib-quarter">' + ql + '</div>'
    + '<span class="rib-dot">\u00b7</span>'
    + '<span class="rib-date">' + ds + '</span>'
    + histBadge
    + '<div class="rib-spacer"></div>'
    + '<div class="rib-wk">'
    +   '<div class="rib-wk-bar"><div class="rib-wk-fill" style="width:' + pp + '%"></div></div>'
    +   '<span class="rib-wk-lbl">' + done + '/' + tot + ' Wk</span>'
    + '</div>'
    + drrStats;
}

function renderHero() {
  var bkAtt  = bk.attainment  || 0;
  var bkHR   = ctx.bookingsForecastAtt || bk.forecastAtt || 0;
  var bkCmt  = com.attainment || 0;
  var pilAtt = pil.attainment  || 0;
  var pilHR  = pil.forecastAtt || 0;
  var pilCmt = com.pilotAtt    || 0;
  var cmpAtt = cmp.value       || 0;

  document.getElementById('ring-block').innerHTML =
    svgRing(cmpAtt, bkAtt, pilAtt)
    + '<div class="ring-legend">'
    +   '<div class="ring-leg"><span class="ring-leg-dot" style="background:' + sc(cmpAtt) + '"></span>Composite ' + pct(cmpAtt) + '</div>'
    +   '<div class="ring-leg"><span class="ring-leg-dot" style="background:' + sc(bkAtt) + '"></span>Bookings ' + pct(bkAtt) + '</div>'
    +   '<div class="ring-leg"><span class="ring-leg-dot" style="background:' + sc(pilAtt) + '"></span>Piloten ' + pct(pilAtt) + '</div>'
    + '</div>';

  document.getElementById('comp-block').innerHTML =
    '<div class="comp-col">'
    +   '<div class="comp-head">'
    +     '<span class="comp-title">Bookings</span>'
    +     '<span class="comp-abs">' + eur(bk.arr) + ' / ' + eur(bk.target) + '</span>'
    +   '</div>'
    +   '<div class="comp-att-row">'
    +     '<span class="comp-att ' + scCls(bkAtt) + '">' + pct(bkAtt) + '</span>'
    +     '<span class="comp-att-sub">TA</span>'
    +   '</div>'
    +   fbar(bkAtt, bkHR, bkCmt)
    + '</div>'
    + '<div class="comp-col">'
    +   '<div class="comp-head">'
    +     '<span class="comp-title">Piloten</span>'
    +     '<span class="comp-abs">' + Math.round(pil.count || 0) + ' / ' + Math.round(pil.target || 0) + '</span>'
    +   '</div>'
    +   '<div class="comp-att-row">'
    +     '<span class="comp-att ' + scCls(pilAtt) + '">' + pct(pilAtt) + '</span>'
    +     '<span class="comp-att-sub">TA</span>'
    +   '</div>'
    +   fbar(pilAtt, pilHR, pilCmt)
    + '</div>';
}

function miniRing(v, color) {
  var r = 20;
  var circ   = parseFloat((2 * Math.PI * r).toFixed(1));
  var offset = parseFloat((circ * (1 - clamp(v) / 100)).toFixed(1));
  return '<svg class="sc-mini-ring" width="54" height="54" viewBox="0 0 54 54">'
    + '<circle cx="27" cy="27" r="' + r + '" fill="none" stroke="var(--sunken)" stroke-width="7"/>'
    + '<circle cx="27" cy="27" r="' + r + '" fill="none" stroke="' + color + '" stroke-width="7"'
    +   ' stroke-linecap="round"'
    +   ' stroke-dasharray="' + circ + ' ' + circ + '"'
    +   ' stroke-dashoffset="' + circ + '"'
    +   ' style="transform:rotate(-90deg);transform-origin:27px 27px;'
    +   '--circ:' + circ + ';--target:' + offset + ';'
    +   'animation:ring-fill .8s var(--smooth) .25s forwards;"/>'
    + '</svg>';
}

function renderSecondary() {
  var covV   = cov.value  || 0;
  var wrV    = wr.value   || 0;
  var staleV = st.value   || 0;

  var covColor  = covV >= 2.5 ? 'var(--green)' : covV >= 1.5 ? 'var(--amber)' : 'var(--red)';
  var covPct    = clamp(covV / 3 * 100);
  var wrColor   = sc(wrV);
  var staleColor= staleV <= 20 ? 'var(--green)' : staleV <= 40 ? 'var(--amber)' : 'var(--red)';
  var health    = 100 - staleV;

  var wowHtml = '';
  if (wow.newArr > 0)    wowHtml += '<span class="tag tag-sky">\u2191 ' + eur(wow.newArr) + ' neu</span>';
  if (wow.wonCWArr > 0)  wowHtml += '<span class="tag tag-green">\u2713 +' + eur(wow.wonCWArr) + '</span>';
  if (wow.lostCWArr > 0) wowHtml += '<span class="tag tag-red">\u2717 -' + eur(wow.lostCWArr) + '</span>';
  if (!wowHtml) wowHtml = '<span class="sc-sub">Keine Pipeline-Bewegung</span>';

  var overdueHtml = '';
  if (st.overdue && st.overdue.count > 0) {
    overdueHtml = '<div style="padding:5px 7px;background:var(--red-dim);border-radius:var(--r-sm)">'
      + '<span style="color:var(--red);font-size:10.5px;font-weight:800">'
      + '\u26a0\ufe0f ' + st.overdue.count + ' \u00fcberf\u00e4llig (' + eur(st.overdue.arr) + ')'
      + '</span></div>';
  }

  var noData = !cov.pipelineARR && covV >= 99;
  var covDisplay = noData ? '\u2014' : covV.toFixed(1) + '\u00d7';
  var covC = noData ? 'var(--text3)' : covColor;

  var cards = [
    '<div class="sc" style="animation-delay:.04s">'
    + '<div class="sc-title">Pipeline Coverage</div>'
    + '<div class="sc-val" style="color:' + covC + '">' + covDisplay + '</div>'
    + '<div class="sc-sub">' + eur(cov.pipelineARR) + ' Pipeline</div>'
    + (!noData ? '<div class="sc-bar"><div class="sc-bar-fill" style="width:' + covPct + '%;background:' + covColor + '"></div></div>' : '')
    + '<div class="sc-sub" style="margin-top:1px">' + (cov.pilotOpps || 0) + ' Pilot Opps (' + eur(cov.pilotArr) + ')</div>'
    + '</div>',

    '<div class="sc" style="animation-delay:.09s">'
    + '<div class="sc-title">Win Rate</div>'
    + '<div class="sc-ring-row">'
    +   miniRing(wrV, wrColor)
