    +   '<span class="funnel-sep">\u2192</span>'
    +   '<div class="funnel-item"><span class="funnel-val">' + (l30.oppPerDay || 0).toFixed(1) + '</span>'
    +     '<span class="funnel-lbl">Opp/d</span>' + arrowHtml(l30.trendOpp) + '</div>'
    + '</div>'
    + '<div class="sc-sub">T\u2192QT ' + (l30.touchToQual || 0) + '% \u00b7 QT\u2192Opp ' + (l30.qualToOpp || 0) + '%</div>'
    + '</div>',

    '<div class="sc" style="animation-delay:.24s">'
    + '<div class="sc-title">Diese Woche</div>'
    + '<div style="display:flex;flex-wrap:wrap;gap:4px">' + wowHtml + '</div>'
    + overdueHtml
    + '</div>',
  ];

  document.getElementById('secondary-grid').innerHTML = cards.join('');
}

function render() {
  try {
    m   = appsmith.model || {};
    ctx = m.context   || {};
    bk  = m.bookings  || {};
    pil = m.piloten   || {};
    cmp = m.composite || {};
    cov = m.coverage  || {};
    wr  = m.winRate   || {};
    act = m.activity  || {};
    st  = m.stale     || {};
    com = ctx.commit  || {};
    wk  = ctx.werktage || {};
    wow = cov.wow     || {};
    l30 = act.l30     || {};
    renderRibbon();
    renderHero();
    renderSecondary();
  } catch (e) {
    document.getElementById('kpi-root').innerHTML =
      '<div style="padding:20px;color:var(--red);font-family:monospace;font-size:12px">'
      + '<strong>Render error:</strong><br>' + e.message + '</div>';
  }
}

appsmith.onReady(function () { render(); });
})();

