@import url('https://fonts.googleapis.com/css2?family=Nunito:wght@400;500;600;700;800;900&display=swap');

:root {
  --bg: #f5f5f7;
  --card: #ffffff;
  --sunken: #f0f0f5;
  --text1: #1d1d1f;
  --text2: #6e6e73;
  --text3: #aeaeb2;
  --green: #34c759;
  --green-dim: rgba(52,199,89,.12);
  --amber: #ff9f0a;
  --amber-dim: rgba(255,159,10,.12);
  --red: #ff3b30;
  --red-dim: rgba(255,59,48,.12);
  --sky: #0ea5e9;
  --sky-dim: rgba(14,165,233,.12);
  --indigo: #6366f1;
  --indigo-dim: rgba(99,102,241,.12);
  --border: rgba(0,0,0,.07);
  --r-sm: 8px; --r-md: 14px; --r-lg: 20px; --r-pill: 9999px;
  --f: 'Nunito', system-ui, sans-serif;
  --smooth: cubic-bezier(.4,0,.2,1);
  --spring: cubic-bezier(.34,1.56,.64,1);
}

*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
body {
  font-family: var(--f);
  background: var(--bg);
  color: var(--text1);
  font-size: 13px;
  line-height: 1.4;
  -webkit-font-smoothing: antialiased;
}

#kpi-root {
  display: flex; flex-direction: column; gap: 10px;
  padding: 10px; min-height: 100%;
}

/* ── Ribbon ────────────────────────────────────────────────────────── */
#ribbon {
  display: flex; align-items: center; gap: 10px;
  background: var(--card); border-radius: var(--r-md);
  padding: 9px 16px; border: 1px solid var(--border);
  flex-wrap: wrap;
}
.rib-quarter { font-weight: 900; font-size: 13px; color: var(--text1); }
.rib-dot { color: var(--text3); }
.rib-date { color: var(--text2); font-size: 12px; font-weight: 500; }
.rib-spacer { flex: 1; }
.rib-wk { display: flex; align-items: center; gap: 7px; }
.rib-wk-bar { width: 72px; height: 5px; background: var(--sunken); border-radius: var(--r-pill); overflow: hidden; }
.rib-wk-fill { height: 100%; background: var(--sky); border-radius: var(--r-pill); }
.rib-wk-lbl { font-size: 11px; color: var(--text2); font-weight: 600; white-space: nowrap; }
.rib-sep { width: 1px; height: 18px; background: var(--border); flex-shrink: 0; }
.rib-kv { display: flex; flex-direction: column; align-items: center; gap: 1px; }
.rib-kv-val { font-size: 13px; font-weight: 800; line-height: 1.1; }
.rib-kv-lbl { font-size: 9.5px; color: var(--text3); text-transform: uppercase; letter-spacing: .5px; }

/* ── Hero ──────────────────────────────────────────────────────────── */
#hero {
  display: flex; gap: 0;
  background: var(--card);
  border-radius: var(--r-lg);
  border: 1px solid var(--border);
  overflow: hidden;
}
#ring-block {
  display: flex; flex-direction: column; align-items: center; justify-content: center;
  gap: 10px; padding: 20px 16px 20px 20px;
  min-width: 196px; flex-shrink: 0;
}
.ring-svg { display: block; }
.ring-track { fill: none; stroke: var(--sunken); stroke-width: 9; }
.ring-arc { fill: none; stroke-width: 9; stroke-linecap: round; transform-origin: center; }
.ring-center-val {
  font-family: var(--f); font-size: 30px; font-weight: 900;
  fill: var(--text1); text-anchor: middle;
}
.ring-center-sub {
  font-family: var(--f); font-size: 11px; font-weight: 700;
  fill: var(--text2); text-anchor: middle;
  text-transform: uppercase; letter-spacing: .5px;
}
.ring-legend { display: flex; gap: 10px; flex-wrap: wrap; justify-content: center; }
.ring-leg { display: flex; align-items: center; gap: 4px; font-size: 11px; color: var(--text2); font-weight: 700; }
.ring-leg-dot { width: 7px; height: 7px; border-radius: 50%; flex-shrink: 0; }

/* ── Components ────────────────────────────────────────────────────── */
#comp-block { display: flex; flex: 1; }
.comp-col {
  flex: 1; display: flex; flex-direction: column; gap: 8px;
  padding: 20px 20px 20px 18px;
  border-left: 1px solid var(--border);
}
.comp-head {
  display: flex; align-items: baseline; justify-content: space-between; gap: 4px;
}
.comp-title { font-size: 10px; font-weight: 700; text-transform: uppercase; letter-spacing: .6px; color: var(--text3); }
.comp-abs { font-size: 12px; font-weight: 700; color: var(--text2); }
.comp-att-row { display: flex; align-items: baseline; gap: 6px; }
.comp-att { font-size: 40px; font-weight: 900; line-height: 1; }
.comp-att-sub { font-size: 12px; color: var(--text2); font-weight: 600; }

/* ── Forecast bar ──────────────────────────────────────────────────── */
.fbar { width: 100%; }
.fbar-track { position: relative; height: 10px; background: var(--sunken); border-radius: var(--r-pill); }
.fbar-actual {
  position: absolute; left: 0; top: 0; height: 100%;
  border-radius: var(--r-pill);
  transform: scaleX(0); transform-origin: left;
  animation: bar-grow .7s var(--smooth) .1s forwards;
  max-width: 100%;
}
.fbar-hr {
  position: absolute; top: 0; height: 100%;
  background: repeating-linear-gradient(90deg, var(--sky) 0, var(--sky) 4px, transparent 4px, transparent 8px);
  border-radius: 0 var(--r-pill) var(--r-pill) 0;
  transform: scaleX(0); transform-origin: left;
  animation: bar-grow .7s var(--smooth) .25s forwards;
  max-width: 100%; overflow: hidden;
}
.fbar-pin {
  position: absolute; top: -5px;
  width: 3px; height: calc(100% + 10px);
  background: var(--indigo); border-radius: 2px;
  transform: translateX(-50%);
  animation: fade-up .4s var(--spring) .6s both;
}
.fbar-pin::after {
  content: ''; position: absolute; bottom: -5px; left: 50%;
  transform: translateX(-50%);
  width: 9px; height: 9px;
  background: var(--indigo); border-radius: 50%;
  border: 2.5px solid white;
  box-shadow: 0 0 0 1.5px var(--indigo);
}
.fbar-labels { display: flex; align-items: center; gap: 6px; margin-top: 7px; flex-wrap: wrap; }
.fbar-l-ist  { font-size: 11px; font-weight: 800; }
.fbar-l-hr   { font-size: 11px; font-weight: 700; color: var(--sky); }
.fbar-l-cmt  { font-size: 11px; font-weight: 700; color: var(--indigo); }
.fbar-l-delta { font-size: 10px; font-weight: 800; padding: 1px 6px; border-radius: var(--r-pill); }
.d-pos { color: var(--indigo); background: var(--indigo-dim); }
.d-neg { color: var(--red);    background: var(--red-dim); }

/* ── Secondary grid ────────────────────────────────────────────────── */
#secondary-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(155px, 1fr));
  gap: 10px;
}
.sc {
  background: var(--card); border-radius: var(--r-md);
  border: 1px solid var(--border);
  padding: 14px 16px;
  display: flex; flex-direction: column; gap: 7px;
  animation: fade-up .45s var(--smooth) both;
}
.sc-title { font-size: 9.5px; font-weight: 700; text-transform: uppercase; letter-spacing: .6px; color: var(--text3); }
.sc-val { font-size: 28px; font-weight: 900; line-height: 1; }
.sc-sub { font-size: 11px; color: var(--text2); font-weight: 600; }
.sc-bar { height: 7px; background: var(--sunken); border-radius: var(--r-pill); overflow: hidden; }
.sc-bar-fill {
  height: 100%; border-radius: var(--r-pill);
  transform: scaleX(0); transform-origin: left;
  animation: bar-grow .7s var(--smooth) .2s forwards;
}
.sc-ring-row { display: flex; align-items: center; gap: 10px; }
.sc-mini-ring { display: block; flex-shrink: 0; }
.funnel { display: flex; align-items: center; gap: 4px; }
.funnel-item { display: flex; flex-direction: column; align-items: center; gap: 1px; }
.funnel-val { font-size: 18px; font-weight: 900; }
.funnel-lbl { font-size: 9px; color: var(--text3); text-transform: uppercase; letter-spacing: .3px; }
.funnel-arr { font-size: 10px; font-weight: 700; }
.funnel-sep { font-size: 13px; color: var(--text3); }
.arrow-up { color: var(--green); }
.arrow-dn  { color: var(--red); }
.arrow-eq  { color: var(--text3); }
.tag {
  display: inline-flex; align-items: center; gap: 3px;
  padding: 3px 7px; border-radius: var(--r-pill);
  font-size: 10.5px; font-weight: 700;
}
.tag-green { color: var(--green); background: var(--green-dim); }
.tag-red   { color: var(--red);   background: var(--red-dim); }
.tag-sky   { color: var(--sky);   background: var(--sky-dim); }
.tag-amber { color: var(--amber); background: var(--amber-dim); }
.c-green  { color: var(--green); }
.c-amber  { color: var(--amber); }
.c-red    { color: var(--red); }

/* ── Animations ────────────────────────────────────────────────────── */
@keyframes ring-fill {
  from { stroke-dashoffset: var(--circ); }
  to   { stroke-dashoffset: var(--target); }
}
@keyframes bar-grow {
  from { transform: scaleX(0); }
  to   { transform: scaleX(1); }
}
@keyframes fade-up {
  from { opacity: 0; transform: translateY(7px); }
  to   { opacity: 1; transform: translateY(0); }
}

/* ── Responsive ────────────────────────────────────────────────────── */
@media (max-width: 680px) {
  #hero { flex-direction: column; }
  #comp-block { flex-direction: column; }
  #ring-block { min-width: unset; padding: 16px; }
  .comp-col { border-left: none; border-top: 1px solid var(--border); }
}

