    +   '<div class="comp-att-row">'
    +     '<span class="comp-att ' + scCls(pilAtt) + '">' + pct(pilAtt) + '</span>'
    +     '<span class="comp-att-sub">TA</span>'
    +   '</div>'
    +   fbar(pilAtt, pilHR, pilCmt)
    + '</div>';
}

function miniRing(v, color) {
  var r = 20;
  var circ   = parseFloat((2 * Math.PI * r).toFixed(1));
  var offset = parseFloat((circ * (1 - clamp(v) / 100)).toFixed(1));
  return '<svg class="sc-mini-ring" width="54" height="54" viewBox="0 0 54 54">'
    + '<circle cx="27" cy="27" r="' + r + '" fill="none" stroke="var(--sunken)" stroke-width="7"/>'
    + '<circle cx="27" cy="27" r="' + r + '" fill="none" stroke="' + color + '" stroke-width="7"'
    +   ' stroke-linecap="round"'
    +   ' stroke-dasharray="' + circ + ' ' + circ + '"'
    +   ' stroke-dashoffset="' + circ + '"'
    +   ' style="transform:rotate(-90deg);transform-origin:27px 27px;'
    +   '--circ:' + circ + ';--target:' + offset + ';'
    +   'animation:ring-fill .8s var(--smooth) .25s forwards;"/>'
    + '</svg>';
}

function renderSecondary() {
  var covV   = cov.value  || 0;
  var wrV    = wr.value   || 0;
  var staleV = st.value   || 0;

  var covColor  = covV >= 2.5 ? 'var(--green)' : covV >= 1.5 ? 'var(--amber)' : 'var(--red)';
  var covPct    = clamp(covV / 3 * 100);
  var wrColor   = sc(wrV);
  var staleColor= staleV <= 20 ? 'var(--green)' : staleV <= 40 ? 'var(--amber)' : 'var(--red)';
  var health    = 100 - staleV;

  var wowHtml = '';
  if (wow.newArr > 0)    wowHtml += '<span class="tag tag-sky">\u2191 ' + eur(wow.newArr) + ' neu</span>';
  if (wow.wonCWArr > 0)  wowHtml += '<span class="tag tag-green">\u2713 +' + eur(wow.wonCWArr) + '</span>';
  if (wow.lostCWArr > 0) wowHtml += '<span class="tag tag-red">\u2717 -' + eur(wow.lostCWArr) + '</span>';
  if (!wowHtml) wowHtml = '<span class="sc-sub">Keine Pipeline-Bewegung</span>';

  var overdueHtml = '';
  if (st.overdue && st.overdue.count > 0) {
    overdueHtml = '<div style="padding:5px 7px;background:var(--red-dim);border-radius:var(--r-sm)">'
      + '<span style="color:var(--red);font-size:10.5px;font-weight:800">'
      + '\u26a0\ufe0f ' + st.overdue.count + ' \u00fcberf\u00e4llig (' + eur(st.overdue.arr) + ')'
      + '</span></div>';
  }

  var noData = !cov.pipelineARR && covV >= 99;
  var covDisplay = noData ? '\u2014' : covV.toFixed(1) + '\u00d7';
  var covC = noData ? 'var(--text3)' : covColor;

  var cards = [
    '<div class="sc" style="animation-delay:.04s">'
    + '<div class="sc-title">Pipeline Coverage</div>'
    + '<div class="sc-val" style="color:' + covC + '">' + covDisplay + '</div>'
    + '<div class="sc-sub">' + eur(cov.pipelineARR) + ' Pipeline</div>'
    + (!noData ? '<div class="sc-bar"><div class="sc-bar-fill" style="width:' + covPct + '%;background:' + covColor + '"></div></div>' : '')
    + '<div class="sc-sub" style="margin-top:1px">' + (cov.pilotOpps || 0) + ' Pilot Opps (' + eur(cov.pilotArr) + ')</div>'
    + '</div>',

    '<div class="sc" style="animation-delay:.09s">'
    + '<div class="sc-title">Win Rate</div>'
    + '<div class="sc-ring-row">'
    +   miniRing(wrV, wrColor)
    +   '<div><div class="sc-val" style="color:' + wrColor + '">' + Math.round(wrV) + '%</div>'
    +   '<div class="sc-sub">' + (wr.wonCount || 0) + 'W / ' + (wr.lostCount || 0) + 'L</div></div>'
    + '</div>'
    + '<div class="sc-sub">' + (wr.demos || 0) + ' Demos \u2192 ' + (wr.pilotOpps || 0) + ' Opps</div>'
    + '</div>',

    '<div class="sc" style="animation-delay:.14s">'
    + '<div class="sc-title">Stale Pipeline</div>'
    + '<div class="sc-val" style="color:' + staleColor + '">' + Math.round(staleV) + '%</div>'
    + '<div class="sc-sub">' + (st.staleCount || 0) + ' von ' + (st.totalOpen || 0) + ' Opps</div>'
    + '<div class="sc-bar"><div class="sc-bar-fill" style="width:' + clamp(health) + '%;background:' + sc(health) + '"></div></div>'
    + '<div class="sc-sub" style="margin-top:1px;color:' + staleColor + '">'
    +   (staleV <= 20 ? '\u2713 Pipeline gesund' : '\u26a0 Aufr\u00e4umen') + '</div>'
    + '</div>',

    '<div class="sc" style="animation-delay:.19s">'
    + '<div class="sc-title">Aktivit\u00e4t \u00d830</div>'
    + '<div class="funnel">'
    +   '<div class="funnel-item"><span class="funnel-val">' + (l30.touchPerDay || 0).toFixed(1) + '</span>'
    +     '<span class="funnel-lbl">Touch/d</span>' + arrowHtml(l30.trendTouch) + '</div>'
    +   '<span class="funnel-sep">\u2192</span>'
    +   '<div class="funnel-item"><span class="funnel-val">' + (l30.qualTouchPerDay || 0).toFixed(1) + '</span>'
    +     '<span class="funnel-lbl">QT/d</span>' + arrowHtml(l30.trendQual) + '</div>'
    +   '<span class="funnel-sep">\u2192</span>'
    +   '<div class="funnel-item"><span class="funnel-val">' + (l30.oppPerDay || 0).toFixed(1) + '</span>'
    +     '<span class="funnel-lbl">Opp/d</span>' + arrowHtml(l30.trendOpp) + '</div>'
    + '</div>'
    + '<div class="sc-sub">T\u2192QT ' + (l30.touchToQual || 0) + '% \u00b7 QT\u2192Opp ' + (l30.qualToOpp || 0) + '%</div>'
    + '</div>',

    '<div class="sc" style="animation-delay:.24s">'
    + '<div class="sc-title">Diese Woche</div>'
    + '<div style="display:flex;flex-wrap:wrap;gap:4px">' + wowHtml + '</div>'
    + overdueHtml
    + '</div>',
  ];

  document.getElementById('secondary-grid').innerHTML = cards.join('');
}

function render() {
  try {
    m   = appsmith.model || {};
    ctx = m.context   || {};
    bk  = m.bookings  || {};
    pil = m.piloten   || {};
    cmp = m.composite || {};
    cov = m.coverage  || {};
    wr  = m.winRate   || {};
    act = m.activity  || {};
    st  = m.stale     || {};
    com = ctx.commit  || {};
    wk  = ctx.werktage || {};
    wow = cov.wow     || {};
    l30 = act.l30     || {};
    renderRibbon();
    renderHero();
    renderSecondary();
  } catch (e) {
    document.getElementById('kpi-root').innerHTML =
      '<div style="padding:20px;color:var(--red);font-family:monospace;font-size:12px">'
      + '<strong>Render error:</strong><br>' + e.message + '</div>';
  }
}

appsmith.onReady(function () { render(); });
})();
